import{_ as e,a as t,b as n,c as i,d,e as l,f as r}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as s,o,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Menambahkan Discord Channel","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/upload/discord.md","filePath":"id-ID/upload/discord.md","lastUpdated":1781962217000}'),p={name:"id-ID/upload/discord.md"};function u(m,a,k,b,g,D){return o(),c("div",null,[...a[0]||(a[0]=[h('<h1 id="menambahkan-discord-channel" tabindex="-1">Menambahkan Discord Channel <a class="header-anchor" href="#menambahkan-discord-channel" aria-label="Permalink to &quot;Menambahkan Discord Channel&quot;">​</a></h1><h2 id="yang-perlu-disiapkan-sebelum-mulai" tabindex="-1">Yang Perlu Disiapkan Sebelum Mulai <a class="header-anchor" href="#yang-perlu-disiapkan-sebelum-mulai" aria-label="Permalink to &quot;Yang Perlu Disiapkan Sebelum Mulai&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Discord account</td><td>Digunakan untuk membuat server, channel, dan developer application.</td></tr><tr><td>Discord server</td><td>Bot harus join server sebelum bisa mengakses channel.</td></tr><tr><td>Text channel</td><td>Images dan files akan dikirim ke channel ini.</td></tr><tr><td>Discord Developer Portal</td><td>Digunakan untuk membuat application, membuat bot, dan mendapatkan <code>Bot Token</code>.</td></tr></tbody></table><h2 id="di-mana-menambahkannya" tabindex="-1">Di Mana Menambahkannya <a class="header-anchor" href="#di-mana-menambahkannya" aria-label="Permalink to &quot;Di Mana Menambahkannya&quot;">​</a></h2><ol><li>Buka System Settings.</li><li>Masuk ke Upload Settings.</li><li>Klik Add Channel di kanan atas.</li><li>Pilih <code>Discord</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Fungsi</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama yang mudah dikenali untuk channel ini, misalnya &quot;Discord Primary&quot;.</td><td>Required</td></tr><tr><td>Bot Token</td><td>Discord bot token.</td><td>Required</td></tr><tr><td>Channel ID</td><td>ID target text channel.</td><td>Required</td></tr><tr><td>Proxy URL (optional)</td><td>Gunakan hanya jika akses Discord CDN tidak stabil. Masukkan full URL, termasuk <code>https://</code>.</td><td>Optional</td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><h3 id="_1-buat-discord-server-dan-text-channel" tabindex="-1">1. Buat Discord Server dan Text Channel <a class="header-anchor" href="#_1-buat-discord-server-dan-text-channel" aria-label="Permalink to &quot;1. Buat Discord Server dan Text Channel&quot;">​</a></h3><ol><li>Buka Discord.</li><li>Buat server baru, atau gunakan existing server milik Anda.</li><li>Buat text channel di server tersebut.</li></ol><p><img src="'+e+'" alt="Create a server" loading="lazy"></p><h3 id="_2-buat-bot-di-discord-developer-portal" tabindex="-1">2. Buat Bot di Discord Developer Portal <a class="header-anchor" href="#_2-buat-bot-di-discord-developer-portal" aria-label="Permalink to &quot;2. Buat Bot di Discord Developer Portal&quot;">​</a></h3><ol><li>Buka Discord Developer Portal: <code>https://discord.com/developers/applications</code></li><li>Klik <code>New Application</code>.</li><li>Masukkan application name dan buat.</li><li>Buka halaman <code>Bot</code> dari left sidebar.</li><li>Generate atau reset token di halaman <code>Bot</code>.</li><li>Simpan token.</li></ol><p>Token ini adalah <code>Bot Token</code> yang perlu dimasukkan ke ImgBed.</p><p><img src="'+t+'" alt="View the bot token" loading="lazy"></p><h3 id="_3-buat-oauth2-invite-link-dan-install-bot" tabindex="-1">3. Buat OAuth2 Invite Link dan Install Bot <a class="header-anchor" href="#_3-buat-oauth2-invite-link-dan-install-bot" aria-label="Permalink to &quot;3. Buat OAuth2 Invite Link dan Install Bot&quot;">​</a></h3><ol><li>Buka halaman <code>OAuth2</code> dari left sidebar.</li><li>Di bagian scopes, pilih <code>bot</code>.</li><li>Di area permission, enable permissions ini:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Required</th></tr></thead><tbody><tr><td>View Channels</td><td>Yes</td></tr><tr><td>Send Messages</td><td>Yes</td></tr><tr><td>Attach Files</td><td>Yes</td></tr><tr><td>Read Message History</td><td>Yes</td></tr></tbody></table><ol start="4"><li>Di bagian bawah page, pastikan integration type adalah <code>Guild Install</code>.</li><li>Copy generated URL.</li><li>Buka URL tersebut di browser.</li><li>Pilih target server.</li><li>Selesaikan authorization flow.</li></ol><p><img src="'+n+'" alt="Select bot permissions in OAuth2" loading="lazy"></p><p><img src="'+i+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-enable-developer-mode-dan-copy-channel-id" tabindex="-1">4. Enable Developer Mode dan Copy Channel ID <a class="header-anchor" href="#_4-enable-developer-mode-dan-copy-channel-id" aria-label="Permalink to &quot;4. Enable Developer Mode dan Copy Channel ID&quot;">​</a></h3><ol><li>Klik gear icon di sebelah avatar Anda di kiri bawah Discord.</li><li>Buka Advanced dari left sidebar.</li><li>Enable Developer Mode.</li><li>Kembali ke target text channel.</li><li>Right-click nama channel.</li><li>Klik Copy Channel ID.</li></ol><p>Angka yang disalin adalah <code>Channel ID</code> yang diperlukan ImgBed.</p><p><img src="'+d+'" alt="Enable developer mode" loading="lazy"></p><p><img src="'+l+'" alt="Copy the channel ID" loading="lazy"></p><h3 id="_5-isi-discord-channel-di-imgbed" tabindex="-1">5. Isi Discord Channel di ImgBed <a class="header-anchor" href="#_5-isi-discord-channel-di-imgbed" aria-label="Permalink to &quot;5. Isi Discord Channel di ImgBed&quot;">​</a></h3><p>Kembali ke channel configuration dialog dan isi field sebagai berikut:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama channel kustom, misalnya <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>Token yang disimpan dari halaman <code>Bot</code> di Discord Developer Portal.</td></tr><tr><td>Channel ID</td><td>Channel ID yang Anda copy dari Discord.</td></tr><tr><td>Proxy URL (optional)</td><td>Hanya jika perlu, misalnya <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>Klik Save setelah selesai.</p><p><img src="'+r+`" alt="Add the Discord channel configuration" loading="lazy"></p><h2 id="cara-memeriksa" tabindex="-1">Cara Memeriksa <a class="header-anchor" href="#cara-memeriksa" aria-label="Permalink to &quot;Cara Memeriksa&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cara Memeriksa</th></tr></thead><tbody><tr><td>Channel card muncul</td><td>Setelah save, halaman Upload Settings harus menampilkan Discord channel card.</td></tr><tr><td>Channel bisa diaktifkan</td><td>Active switch seharusnya tetap on.</td></tr><tr><td>Configuration tersimpan</td><td>Detail view harus menunjukkan Bot Token dan Channel ID sudah tersimpan.</td></tr><tr><td>Upload berjalan</td><td>Upload test image dan pastikan muncul di target Discord text channel.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buat Discord server</span></span>
<span class="line"><span>-&gt; Buat text channel</span></span>
<span class="line"><span>-&gt; Buat bot di Discord Developer Portal</span></span>
<span class="line"><span>-&gt; Simpan Bot Token dari halaman Bot</span></span>
<span class="line"><span>-&gt; Di OAuth2, pilih bot, View Channels, Send Messages, Attach Files, dan Read Message History</span></span>
<span class="line"><span>-&gt; Copy generated URL dan authorize bot untuk target server</span></span>
<span class="line"><span>-&gt; Pastikan target text channel memberikan permissions yang sama</span></span>
<span class="line"><span>-&gt; Enable Developer Mode</span></span>
<span class="line"><span>-&gt; Right-click target text channel dan copy Channel ID</span></span>
<span class="line"><span>-&gt; Masukkan Bot Token dan Channel ID di ImgBed</span></span>
<span class="line"><span>-&gt; Save dan upload test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const _=s(p,[["render",u]]);export{f as __pageData,_ as default};
